func solve(s string, k int64) string {
    var result []byte
    for _, char := range s {
        switch char {
        case '*':
            if len(result) > 0 {
                result = result[:len(result)-1]
            }
        case '#':
            copy(result[len(result):], result)
        case '%':
            result = reverse(result)
        default:
            result = append(result, byte(char))
        }
    }
    if k < 0 || k >= int64(len(result)) {
        return "."
    }
    return string(result[k])
}

func reverse(b []byte) []byte {
    for i, j := 0, len(b)-1; i < j; i, j = i+1, j-1 {
        b[i], b[j] = b[j], b[i]
    }
    return b
}
